for pair, sections in replacements.items():
    # Replace 相性解説
    pattern_kaisetsu = re.compile(r'(## vs \[' + pair + r'\].*?### 相性解説\n\n)(.*?)(?=\n\n### 一緒に楽しむコツ)', re.DOTALL)
    text = pattern_kaisetsu.sub(r'\g<1>' + sections["相性解説"], text)
    
    # Replace 一緒に楽しむコツ
    pattern_kotsu = re.compile(r'(## vs \[' + pair + r'\].*?### 一緒に楽しむコツ\n\n)(.*?)(?=\n\n### 摩擦ポイント)', re.DOTALL)
    text = pattern_kotsu.sub(r'\g<1>' + sections["一緒に楽しむコツ"], text)
    
    # Replace 摩擦ポイント
    pattern_masatsu = re.compile(r'(## vs \[' + pair + r'\].*?### 摩擦ポイント\n\n)(.*?)(?=\n\n### 目的の持ち方)', re.DOTALL)
    text = pattern_masatsu.sub(r'\g<1>' + sections["摩擦ポイント"], text)

